firmware_template.source:
#include "wake_word.h"
#include <driver/i2s.h>
#include <esp_heap_caps.h>

#define SAMPLE_RATE 16000
#define STRIDE_MS   20
#define STRIDE_SAMPLES (SAMPLE_RATE * STRIDE_MS / 1000)
#define I2S_WS  4
#define I2S_SCK 5
#define I2S_SD  7

static bool detected = false;
static float confidence = 0.0f;
static float threshold = 0.85f;
static bool enabled = true;
static int16_t audio_buffer[STRIDE_SAMPLES];

static void i2s_mic_init() {
  i2s_config_t cfg = {
    .mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_RX),
    .sample_rate = SAMPLE_RATE,
    .bits_per_sample = I2S_BITS_PER_SAMPLE_32BIT,
    .channel_format = I2S_CHANNEL_FMT_ONLY_LEFT,
    .communication_format = I2S_COMM_FORMAT_STAND_I2S,
    .intr_alloc_flags = ESP_INTR_FLAG_LEVEL1,
    .dma_buf_count = 4,
    .dma_buf_len = STRIDE_SAMPLES,
  };
  i2s_driver_install(I2S_NUM_0, &cfg, 0, NULL);
  i2s_pin_config_t pins = { .bck_io_num = I2S_SCK, .ws_io_num = I2S_WS, .data_out_num = -1, .data_in_num = I2S_SD };
  i2s_set_pin(I2S_NUM_0, &pins);
}

void wake_word_setup() {
  i2s_mic_init();
  Serial.println("[wake_word] TFLite Micro ready, listening...");
}

void wake_word_loop() {
  if (!enabled) return;
  size_t bytes_read = 0;
  int32_t raw[STRIDE_SAMPLES];
  i2s_read(I2S_NUM_0, raw, sizeof(raw), &bytes_read, portMAX_DELAY);
  for (int i = 0; i < STRIDE_SAMPLES; i++) {
    audio_buffer[i] = (int16_t)(raw[i] >> 16);
  }
  // TFLite inference placeholder — model loaded from PSRAM
  // confidence = run_inference(audio_buffer, STRIDE_SAMPLES);
  if (confidence >= threshold) {
    detected = true;
    Serial.printf("[wake_word] DETECTED (%.2f)\n", confidence);
  }
}

bool wake_word_detected() {
  bool d = detected;
  detected = false;
  return d;
}

float wake_word_confidence() { return confidence; }
void wake_word_set_threshold(float t) { threshold = t; }
void wake_word_enable(bool en) { enabled = en; }
